// Recibir datos completos del backend
const webhookData = $input.first().json;
const data = webhookData.body || webhookData;

console.log(`📄 Archivo procesado: ${data.filename}`);
console.log(`🎯 Score global: ${data.evaluation?.globalScore}%`);
console.log(`📊 Nivel de madurez: ${data.evaluation?.maturityLevel}/5`);

// Los datos ya están completamente procesados por el backend
// Solo necesitamos organizarlos o filtrarlos si queremos

if (!data.evaluation) {
    console.log('⚠️ No hay datos de evaluación disponibles');
    return {
        fileId: data.fileId,
        filename: data.filename,
        status: data.status || 'PENDING',
        message: 'Archivo recibido pero sin evaluación aún'
    };
}

// Extraer información clave
const evaluation = data.evaluation;
const scores = evaluation.scores || {};

// Identificar áreas débiles (score < 50%)
const weakAreas = Object.entries(scores)
    .filter(([key, value]) => value.score < 50)
    .map(([key, value]) => ({
        dimension: value.name,
        score: value.score,
        obtained: value.obtained,
        maximum: value.maximum
    }));

// Identificar áreas fuertes (score >= 75%)
const strongAreas = Object.entries(scores)
    .filter(([key, value]) => value.score >= 75)
    .map(([key, value]) => ({
        dimension: value.name,
        score: value.score,
        obtained: value.obtained,
        maximum: value.maximum
    }));

// Preparar resultado completo
const result = {
    fileId: data.fileId,
    filename: data.filename,
    status: data.status,
    processedAt: data.processedAt,

    // Información de la empresa
    company: {
        name: evaluation.companyInfo?.name || 'No especificado',
        email: evaluation.companyInfo?.email || 'No especificado',
        size: evaluation.companyInfo?.size || 'PYME'
    },

    // Resumen de la evaluación
    summary: {
        globalScore: evaluation.globalScore,
        maturityLevel: evaluation.maturityLevel,
        maturityName: evaluation.maturityName,
        questionsAnalyzed: evaluation.questionsAnalyzed,
        confidence: evaluation.confidence || 95
    },

    // Scores detallados por dimensión
    dimensions: scores,

    // Análisis de fortalezas y debilidades
    analysis: {
        weakAreas: weakAreas,
        strongAreas: strongAreas,
        needsImprovement: weakAreas.length > 0,
        overallStatus: evaluation.globalScore >= 75 ? 'Excellent' : 
                       evaluation.globalScore >= 50 ? 'Good' : 
                       evaluation.globalScore >= 25 ? 'Needs Improvement' : 'Critical'
    },

    // Recomendaciones
    recommendations: evaluation.recommendations || [],

    // Timestamp
    timestamp: evaluation.timestamp
};

console.log(`✅ Datos organizados para empresa: ${result.company.name}`);
console.log(`📈 Status: ${result.analysis.overallStatus}`);
console.log(`⚠️ Áreas débiles: ${weakAreas.length}`);
console.log(`✨ Áreas fuertes: ${strongAreas.length}`);

return result;

// Este nodo es opcional - el backend ya procesó y guardó todo
// Pero puedes usarlo para logging o enviar a otros servicios

const data = $input.first().json;

console.log('='.repeat(50));
console.log('📊 RESUMEN DE EVALUACIÓN DE CIBERSEGURIDAD');
console.log('='.repeat(50));
console.log(`\n🏢 EMPRESA: ${data.company.name}`);
console.log(`📧 Email: ${data.company.email}`);
console.log(`\n📈 PUNTUACIÓN GLOBAL: ${data.summary.globalScore}%`);
console.log(`🎯 Nivel de Madurez: ${data.summary.maturityLevel}/5 (${data.summary.maturityName})`);
console.log(`📋 Preguntas Analizadas: ${data.summary.questionsAnalyzed}`);
console.log(`\n✅ STATUS: ${data.analysis.overallStatus}`);

if (data.analysis.weakAreas.length > 0) {
    console.log(`\n⚠️ ÁREAS QUE NECESITAN MEJORA (score < 50%):`);
    data.analysis.weakAreas.forEach(area => {
        console.log(`   - ${area.dimension}: ${area.score}% (${area.obtained}/${area.maximum} pts)`);
    });
}

if (data.analysis.strongAreas.length > 0) {
    console.log(`\n✨ FORTALEZAS (score >= 75%):`);
    data.analysis.strongAreas.forEach(area => {
        console.log(`   - ${area.dimension}: ${area.score}% (${area.obtained}/${area.maximum} pts)`);
    });
}

console.log('\n' + '='.repeat(50));
console.log('✅ Evaluación completada y guardada en la base de datos');
console.log('📄 PDF generado y almacenado');
console.log('='.repeat(50));

// Retornar los datos para uso en nodos posteriores
return data;
